if ( (edrString(DETAIL.RECORD_TYPE)=="060") or
     (edrString(DETAIL.RECORD_TYPE)=="029") )
{
  //for VASrecord and MSSrecords
  depth  = "8";
}
else if (edrString(DETAIL.RECORD_TYPE)=="050")
{
  //for SCUrecord
  depth  = "7";
}
else if ( (edrString(DETAIL.RECORD_TYPE)=="021") or
          (edrString(DETAIL.RECORD_TYPE)=="031") or
