const String severe     = "severe";
const String warning    = "warning";
const String tag        = "65";
const String arrayIndex = "-1";

RULEITEM_ROW.RULEITEM_RESULT:
String offset = longToStr( edrFieldTokenBytePos( DETAIL.ASS_CBD.CP.CHARGEABLE_QUANTITY_VALUE ));
String depth  = "0";
if ( (edrString(DETAIL.RECORD_TYPE)=="060") or
     (edrString(DETAIL.RECORD_TYPE)=="029") )
{
  //for VASrecord and MSSrecords
  depth  = "8";
}
else if (edrString(DETAIL.RECORD_TYPE)=="050")
{
  //for SCUrecord
  depth  = "7";
}
else if ( (edrString(DETAIL.RECORD_TYPE)=="021") or
          (edrString(DETAIL.RECORD_TYPE)=="031") or
          (edrString(DETAIL.RECORD_TYPE)=="040") or
          (edrString(DETAIL.RECORD_TYPE)=="042") )
{
  //use the same processing for MOC/MTC/GPRS
  if (edrString(DETAIL.ASS_CBD.CP.PRODUCTCODE_USED)=="CAMEL")
  {
    //for CAMELservice
    depth  = "8";
  }
  else if (edrString(DETAIL.ASS_CBD.CP.PRODUCTCODE_USED)!="")
  {
    //for VASservice - same processing for MOC/MTC/GPRS
    depth  = "9";
  }
  else
  {
    //for SSservice, BASICservice, or GPRSservice
    if ( (edrString(DETAIL.RECORD_TYPE)=="040") or
         (edrString(DETAIL.RECORD_TYPE)=="042") )
    {
      //for GPRSservice
      depth  = "9";
    }
    else
    {
      //we cannot make a difference between SSservice, BASICservice, so take it as BASIC
      depth  = "10";
    }
  }
}

edrString( DETAIL.ERROR_REJECT_TYPE ) = "ERR_TAP3_RET";
edrSetIsValidDetail(false);
edrAddError("ERR_TAP3_RET",3,severe,"20",tag,depth,offset,arrayIndex,ruleID);

